from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language sentence from a list of Triple objects."""
    if not triples:
        return ""
    def render(t: Triple) -> str:
        s, p, o = t.subject, t.predicate, t.object
        # Specific phrasing for common predicates
        if p == "country":
            return f"{s} is based in {o}"
        if p == "foundingDate":
            return f"{s} was founded on {o}"
        if p == "industry":
            return f"{s} operates in the {o}"
        if p == "city":
            return f"{s} is headquartered in {o}"
        if p in {"netIncome", "operatingIncome", "revenue"}:
            return f"{s}'s {p} is {o}"
        if p == "leader":
            return f"The leader of {s} is {o}"
        if p == "leaderTitle":
            return f"The leader of {s} holds the title {o}"
        if p == "populationTotal":
            return f"{s} has a population of {o}"
        # Fallback generic rendering
        return f"{s} {p} {o}"
    clauses = [render(t) for t in triples]
    if len(clauses) == 1:
        sentence = clauses[0]
    else:
        sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1]
    return sentence.rstrip() + "."

# EVOLVE-BLOCK-END

